eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   SAMPLE_COURSES: () => (/* binding */ SAMPLE_COURSES)\n/* harmony export */ });\nconst SAMPLE_COURSES = [\n    {\n        title: \"Pretty Girl, Save Yourself: Personal Safety Foundations\",\n        slug: \"personal-safety-foundations\",\n        excerpt: \"The foundational SafeHers curriculum. Learn situational awareness, instinct, secure movement, and personal protection protocols.\",\n        description: \"Based on the book 30 Ways Pretty Girls Can Save Themselves, this course teaches the core safety principles every woman should know. From recognising danger signals to building personal security protocols, you will leave equipped with practical knowledge you can use immediately.\",\n        category: \"personal-safety\",\n        level: \"beginner\",\n        durationHours: 6,\n        instructor: \"Zarinah Knows\",\n        isFree: true,\n        isPublished: true,\n        tags: [\n            \"personal-safety\",\n            \"awareness\",\n            \"foundation\",\n            \"self-defence\"\n        ],\n        learningOutcomes: [\n            \"Identify and respond to common threat patterns\",\n            \"Build a personal safety protocol for daily routines\",\n            \"Understand body language and environmental awareness\",\n            \"Create and maintain a trusted safety circle\",\n            \"Respond effectively to confrontational situations\",\n            \"Develop a personal emergency plan\"\n        ],\n        modules: [\n            {\n                title: \"Understanding Your Safety Landscape\",\n                slug: \"safety-landscape\",\n                description: \"Learn to read your environment and recognise risk before it becomes danger.\",\n                order: 0,\n                lessons: [\n                    {\n                        title: \"Welcome to SafeHer Academy\",\n                        slug: \"welcome\",\n                        type: \"text\",\n                        durationMinutes: 5,\n                        order: 0,\n                        quizQuestions: [],\n                        content: \"Welcome to Pretty Girl, Save Yourself — the foundational course from SafeHer Foundation. This programme is built on decades of security expertise and designed for women across Africa. Over the next modules, you will learn practical, evidence-based safety skills you can use immediately.\\n\\nThis course is based on the book 30 Ways Pretty Girls Can Save Themselves by Zarinah Knows. It has been adapted for the African context in collaboration with DK Cyber.\\n\\nBy the end of this course, you will have a personal safety protocol, a trusted safety circle, and the confidence to protect yourself in everyday situations.\"\n                    },\n                    {\n                        title: \"The 30 Ways Framework\",\n                        slug: \"30-ways-framework\",\n                        type: \"text\",\n                        durationMinutes: 15,\n                        order: 1,\n                        quizQuestions: [],\n                        content: \"The 30 Ways framework was developed by Zarinah Knows over nearly a decade of teaching teen girls and women. It covers four pillars:\\n\\n1. Personal Awareness — knowing your environment and trusting your instincts\\n2. Home Safety — securing the place you sleep\\n3. Digital Security — protecting your online presence and devices\\n4. Financial Protection — safeguarding your money and independence\\n\\nEach pillar builds on the last. In this course, we focus on Personal Awareness and the daily protocols that keep you safe.\"\n                    },\n                    {\n                        title: \"Situational Awareness: The Colour Code\",\n                        slug: \"situational-awareness\",\n                        type: \"text\",\n                        durationMinutes: 20,\n                        order: 2,\n                        quizQuestions: [\n                            {\n                                question: \"What does 'Condition Yellow' mean in the awareness colour code?\",\n                                options: [\n                                    \"Completely relaxed and unaware\",\n                                    \"Relaxed but alert, scanning your environment\",\n                                    \"Specific threat identified\",\n                                    \"Active danger, fight or flight\"\n                                ],\n                                correctIndex: 1,\n                                explanation: \"Condition Yellow is the ideal everyday state — relaxed but deliberately aware of your surroundings.\"\n                            },\n                            {\n                                question: \"What is the first step in situational awareness?\",\n                                options: [\n                                    \"Running away from danger\",\n                                    \"Observing your environment\",\n                                    \"Calling the police\",\n                                    \"Ignoring strangers\"\n                                ],\n                                correctIndex: 1,\n                                explanation: \"Observation is the foundation — you must first notice before you can assess and respond.\"\n                            }\n                        ],\n                        content: \"Situational awareness is the foundation of personal safety. It means paying deliberate attention to what is happening around you — who is near you, what is normal for the environment, and what feels out of place.\\n\\nThe Colour Code of Awareness:\\n\\n• White — Unaware, distracted (headphones in, phone out, not looking around). This is when you are most vulnerable.\\n• Yellow — Relaxed but alert. You are aware of who is around you and what is normal. This should be your default state in public.\\n• Orange — Something has caught your attention. A person, a vehicle, a situation that feels off. You have a specific concern.\\n• Red — A threat is confirmed. You act: move, call for help, defend.\\n\\nPractical Task: For the next 3 days, practice staying in Condition Yellow whenever you leave your home. Notice who is around you, what vehicles are nearby, and where the exits are.\"\n                    }\n                ]\n            },\n            {\n                title: \"Personal Security Protocols\",\n                slug: \"personal-protocols\",\n                description: \"Build daily habits and protocols that make you a harder target.\",\n                order: 1,\n                lessons: [\n                    {\n                        title: \"Building Your Safety Circle\",\n                        slug: \"safety-circle\",\n                        type: \"text\",\n                        durationMinutes: 15,\n                        order: 0,\n                        quizQuestions: [\n                            {\n                                question: \"How many people should be in your safety circle?\",\n                                options: [\n                                    \"1\",\n                                    \"2-4\",\n                                    \"10+\",\n                                    \"Everyone you know\"\n                                ],\n                                correctIndex: 1,\n                                explanation: \"A safety circle of 2-4 trusted people is manageable and reliable.\"\n                            }\n                        ],\n                        content: \"A safety circle is a small group of 2-4 trusted people who know your routines, can be reached in an emergency, and will act without hesitation.\\n\\nHow to build yours:\\n1. Choose people who are reliable, available, and trustworthy — not just close friends\\n2. Share your daily routine with them (work schedule, regular routes)\\n3. Agree on check-in protocols (e.g. text when you arrive home)\\n4. Establish a code word that means 'I need help immediately'\\n5. Test it — send the code word and see how fast they respond\\n\\nPractical Task: Identify your 2-4 safety circle members. Have the conversation with each of them this week. Set up a group chat with a clear name.\"\n                    },\n                    {\n                        title: \"Route Security and Daily Patterns\",\n                        slug: \"route-security\",\n                        type: \"text\",\n                        durationMinutes: 15,\n                        order: 1,\n                        quizQuestions: [\n                            {\n                                question: \"Why should you vary your daily route?\",\n                                options: [\n                                    \"To explore new places\",\n                                    \"To avoid traffic\",\n                                    \"To disrupt predictable patterns\",\n                                    \"To get exercise\"\n                                ],\n                                correctIndex: 2,\n                                explanation: \"Varying routes makes it harder for anyone to anticipate your movements.\"\n                            }\n                        ],\n                        content: \"Most threats exploit predictability. If you take the same route at the same time every day, an attacker can plan around your pattern.\\n\\nRoute Security Basics:\\n• Have at least 3 different routes to your regular destinations\\n• Vary your departure times by 10-15 minutes\\n• Know the safe spots on each route (shops, petrol stations, police posts)\\n• Share your location with your safety circle when travelling alone\\n• Avoid shortcuts through isolated areas, especially after dark\\n\\nPractical Task: Map out 3 different routes from your home to your most frequent destination. Identify at least 2 safe spots on each route.\"\n                    },\n                    {\n                        title: \"Responding to Being Followed\",\n                        slug: \"being-followed\",\n                        type: \"text\",\n                        durationMinutes: 20,\n                        order: 2,\n                        quizQuestions: [],\n                        content: \"If you suspect you are being followed:\\n\\n1. Do NOT go home — you will reveal where you live\\n2. Change your pace — speed up or slow down and see if they match\\n3. Cross the street — do they cross too?\\n4. Make 4 right turns — if they are still behind you after a full square, you are being followed\\n5. Head to a populated, well-lit area — a busy shop, a petrol station, a police post\\n6. Call your safety circle — use your code word\\n7. If approached, make noise — attract attention\\n\\nPractical Task: Walk through the 4-right-turn test mentally for your neighbourhood. Know where you would go.\"\n                    }\n                ]\n            },\n            {\n                title: \"Emergency Preparedness\",\n                slug: \"emergency-prep\",\n                description: \"Plan for the worst so you can respond with clarity.\",\n                order: 2,\n                lessons: [\n                    {\n                        title: \"Your Emergency Contact Plan\",\n                        slug: \"emergency-contacts\",\n                        type: \"activity\",\n                        durationMinutes: 20,\n                        order: 0,\n                        quizQuestions: [],\n                        content: \"Every woman should have an emergency contact plan — a list of numbers you can reach without thinking, stored both in your phone and on paper.\\n\\nYour plan should include:\\n• Local police emergency number\\n• Nearest police station direct line\\n• Hospital/clinic nearest to your home and workplace\\n• Your safety circle (2-4 people)\\n• A trusted family member\\n• DOVVSU (Domestic Violence & Victim Support Unit) if in Ghana: 0800-111-222\\n\\nPractical Task: Fill out your Emergency Contact Plan in the SafeHer Academy Safety Plan. Store a physical copy in your bag.\"\n                    },\n                    {\n                        title: \"De-escalation and Boundary Setting\",\n                        slug: \"de-escalation\",\n                        type: \"text\",\n                        durationMinutes: 20,\n                        order: 1,\n                        quizQuestions: [\n                            {\n                                question: \"What is the best first response when a stranger becomes aggressive?\",\n                                options: [\n                                    \"Fight back immediately\",\n                                    \"Create distance and use a firm voice\",\n                                    \"Freeze and hope they leave\",\n                                    \"Argue your point\"\n                                ],\n                                correctIndex: 1,\n                                explanation: \"Creating physical distance while using a confident, firm voice is the safest first response.\"\n                            }\n                        ],\n                        content: \"De-escalation is the art of reducing tension before a situation becomes physical. It is not weakness — it is strategy.\\n\\nKey principles:\\n• Maintain distance — never let an aggressor get within arm's reach\\n• Use a firm, calm voice — not aggressive, not pleading\\n• Set clear boundaries: 'Stop. Do not come closer.'\\n• Keep your hands visible and in front of you\\n• Look for exits — always know where you can move\\n• Do not turn your back on a threat\\n\\nIf de-escalation fails, your priority is escape, not confrontation.\"\n                    },\n                    {\n                        title: \"Course Review and Safety Plan\",\n                        slug: \"course-review\",\n                        type: \"quiz\",\n                        durationMinutes: 15,\n                        order: 2,\n                        quizQuestions: [\n                            {\n                                question: \"What is Condition Yellow?\",\n                                options: [\n                                    \"Completely unaware\",\n                                    \"Relaxed but alert\",\n                                    \"Specific threat identified\",\n                                    \"Active danger\"\n                                ],\n                                correctIndex: 1,\n                                explanation: \"Yellow is your default public awareness state.\"\n                            },\n                            {\n                                question: \"What should you NOT do if you think you are being followed?\",\n                                options: [\n                                    \"Cross the street\",\n                                    \"Go directly home\",\n                                    \"Head to a busy area\",\n                                    \"Call your safety circle\"\n                                ],\n                                correctIndex: 1,\n                                explanation: \"Never lead a follower to your home.\"\n                            },\n                            {\n                                question: \"How many routes should you have to regular destinations?\",\n                                options: [\n                                    \"1\",\n                                    \"At least 3\",\n                                    \"It doesn't matter\",\n                                    \"As many as possible\"\n                                ],\n                                correctIndex: 1,\n                                explanation: \"At least 3 routes prevents pattern predictability.\"\n                            }\n                        ],\n                        content: \"Final review quiz. Complete this to earn your certificate.\"\n                    }\n                ]\n            }\n        ]\n    },\n    {\n        title: \"Mobile Money Fraud and Financial Safety\",\n        slug: \"mobile-money-fraud\",\n        excerpt: \"Protect yourself from mobile money fraud, SIM swap attacks, and financial scams targeting women across Africa.\",\n        description: \"Mobile money has transformed life across Africa — but it has also created new fraud vectors. This course covers MoMo fraud, SIM swap attacks, fake agent scams, and financial safety practices built for African digital economies.\",\n        category: \"financial-safety\",\n        level: \"beginner\",\n        durationHours: 4,\n        instructor: \"DK Cyber\",\n        isFree: true,\n        isPublished: true,\n        tags: [\n            \"mobile-money\",\n            \"fraud\",\n            \"financial-safety\",\n            \"momo\"\n        ],\n        learningOutcomes: [\n            \"Identify common mobile money fraud techniques\",\n            \"Protect your MoMo and bank accounts from SIM swap attacks\",\n            \"Recognise fake agent and wrong-transfer scams\",\n            \"Set up account security and transaction alerts\",\n            \"Report fraud to the correct authorities\"\n        ],\n        modules: [\n            {\n                title: \"The Mobile Money Threat Landscape\",\n                slug: \"momo-threats\",\n                description: \"Understand how mobile money fraud works in Ghana, Nigeria, and across Africa.\",\n                order: 0,\n                lessons: [\n                    {\n                        title: \"How Mobile Money Fraud Works\",\n                        slug: \"how-fraud-works\",\n                        type: \"text\",\n                        durationMinutes: 20,\n                        order: 0,\n                        quizQuestions: [],\n                        content: \"Mobile money fraud in Africa follows predictable patterns. The most common techniques:\\n\\n1. Fake customer service calls — someone calls pretending to be MTN, Vodafone, or your bank and asks for your PIN\\n2. Wrong transfer scams — a stranger sends money 'by mistake' and asks you to return it (the original transfer is reversed after you send your own money)\\n3. SIM swap attacks — a fraudster convinces your mobile operator to transfer your number to a new SIM\\n4. Social engineering via WhatsApp — fake prize notifications, loan offers, or romance scams\\n5. Fake agent fraud — someone poses as a mobile money agent and asks you to dial a code\\n\\nRule #1: No legitimate operator will ever call you and ask for your PIN. Ever.\"\n                    },\n                    {\n                        title: \"SIM Swap Attacks Explained\",\n                        slug: \"sim-swap\",\n                        type: \"text\",\n                        durationMinutes: 15,\n                        order: 1,\n                        quizQuestions: [\n                            {\n                                question: \"What is a SIM swap attack?\",\n                                options: [\n                                    \"Physically stealing someone's phone\",\n                                    \"Transferring a phone number to a new SIM card\",\n                                    \"Hacking a phone's operating system\",\n                                    \"Cloning a SIM card\"\n                                ],\n                                correctIndex: 1,\n                                explanation: \"SIM swap attacks involve social engineering the mobile operator to transfer your number.\"\n                            }\n                        ],\n                        content: \"A SIM swap attack is when a fraudster convinces your mobile operator to transfer your number to a new SIM card they control. Once they have your number, they can:\\n• Access your mobile money accounts\\n• Reset your passwords\\n• Intercept your verification codes\\n\\nSigns your SIM has been swapped:\\n• Your phone suddenly loses signal\\n• You cannot make calls or send texts\\n• You receive notifications about changes you did not make\\n\\nHow to protect yourself:\\n• Set a SIM PIN with your operator\\n• Never share your ID number with callers\\n• Register for SIM swap alerts\\n• Use app-based 2FA instead of SMS 2FA where possible\"\n                    },\n                    {\n                        title: \"Fake Agent and Reversal Scams\",\n                        slug: \"fake-agents\",\n                        type: \"text\",\n                        durationMinutes: 15,\n                        order: 2,\n                        quizQuestions: [\n                            {\n                                question: \"If a stranger sends you money 'by mistake' and asks you to send it back, what should you do?\",\n                                options: [\n                                    \"Send it back immediately\",\n                                    \"Keep the money\",\n                                    \"Do nothing — tell them to contact their operator\",\n                                    \"Block them\"\n                                ],\n                                correctIndex: 2,\n                                explanation: \"Never send money back directly — the original transfer can be reversed, leaving you out of pocket.\"\n                            }\n                        ],\n                        content: \"Fake agent scams and wrong-transfer scams are extremely common:\\n\\nFake Agent Scam:\\nSomeone approaches you pretending to be a mobile money agent. They ask you to dial a code 'to receive your money.' The code actually transfers money FROM your account.\\n\\nWrong Transfer Scam:\\nA stranger sends money to your account and then contacts you saying it was a mistake. They ask you to send it back. After you do, they reverse the original transaction — and now you have lost your own money.\\n\\nProtection:\\n• Never dial codes given to you by strangers\\n• If someone sends you money 'by mistake,' tell them to contact their operator\\n• Only use verified mobile money agents with proper signage and ID\"\n                    },\n                    {\n                        title: \"Setting Up Financial Security\",\n                        slug: \"financial-security\",\n                        type: \"activity\",\n                        durationMinutes: 20,\n                        order: 3,\n                        quizQuestions: [],\n                        content: \"Practical security setup:\\n\\n1. Set a SIM PIN with your mobile operator today\\n2. Enable transaction alerts (SMS or push notifications) for all MoMo accounts\\n3. Set up app-based 2FA (Google Authenticator) on any account that supports it\\n4. Never share your MoMo PIN with anyone — including family\\n5. Use a different PIN for your phone lock, SIM, and MoMo\\n6. Register your MoMo account with your real ID (makes recovery easier if compromised)\\n\\nPractical Task: Complete all 6 steps above today. Check each one off in your SafeHer Academy Safety Plan.\"\n                    },\n                    {\n                        title: \"Reporting Fraud and Recovery\",\n                        slug: \"reporting-fraud\",\n                        type: \"text\",\n                        durationMinutes: 15,\n                        order: 4,\n                        quizQuestions: [\n                            {\n                                question: \"What is the FIRST thing you should do if you suspect your MoMo account has been compromised?\",\n                                options: [\n                                    \"Post about it on social media\",\n                                    \"Call the police\",\n                                    \"Lock your MoMo account immediately\",\n                                    \"Wait and see if money is taken\"\n                                ],\n                                correctIndex: 2,\n                                explanation: \"Lock your account first to prevent further losses, then report.\"\n                            }\n                        ],\n                        content: \"If you have been defrauded:\\n\\n1. Lock your MoMo account immediately — call your operator's fraud line\\n2. Report to your mobile operator (MTN: 100, Vodafone: 100)\\n3. File a police report at your local station\\n4. Report to the Economic and Organised Crime Office (EOCO) if in Ghana\\n5. Keep all evidence — screenshots, call logs, transaction IDs\\n6. Do NOT engage further with the fraudster\\n\\nPractical Task: Save your operator's fraud hotline in your phone right now.\"\n                    }\n                ]\n            }\n        ]\n    },\n    {\n        title: \"Phone Privacy and Spy App Detection\",\n        slug: \"phone-privacy-spy-detection\",\n        excerpt: \"Learn to detect spyware, secure your phone, and protect your digital privacy from intimate partner surveillance.\",\n        description: \"Your phone knows everything about you. This course teaches you how to check for spy apps, lock down your device, manage app permissions, and protect yourself from digital surveillance — whether from a partner, a stranger, or a scammer.\",\n        category: \"online-safety\",\n        level: \"beginner\",\n        durationHours: 3,\n        instructor: \"DK Cyber\",\n        isFree: true,\n        isPublished: true,\n        tags: [\n            \"phone-privacy\",\n            \"spyware\",\n            \"digital-safety\",\n            \"surveillance\"\n        ],\n        learningOutcomes: [\n            \"Check your phone for spy apps and stalkerware\",\n            \"Configure privacy settings on Android and iPhone\",\n            \"Manage app permissions to protect personal data\",\n            \"Detect signs of digital surveillance\",\n            \"Secure your accounts with strong passwords and 2FA\"\n        ],\n        modules: [\n            {\n                title: \"Is Your Phone Compromised?\",\n                slug: \"phone-compromised\",\n                description: \"Learn the warning signs and how to check your device.\",\n                order: 0,\n                lessons: [\n                    {\n                        title: \"Signs Your Phone May Have Spyware\",\n                        slug: \"spyware-signs\",\n                        type: \"text\",\n                        durationMinutes: 15,\n                        order: 0,\n                        quizQuestions: [],\n                        content: \"Spyware and stalkerware are apps that secretly monitor your calls, messages, location, and photos. They are often installed by intimate partners, but can also come from malicious links.\\n\\nWarning signs:\\n• Battery drains faster than usual\\n• Phone is hot even when not in use\\n• Unusual data usage spikes\\n• Phone takes longer to shut down\\n• You see apps you do not recognise\\n• Someone knows things they should not (your location, your messages)\\n\\nImportant: If you suspect an intimate partner has installed spyware, do NOT confront them before securing yourself. Contact a trusted person first.\"\n                    },\n                    {\n                        title: \"How to Check for Spy Apps\",\n                        slug: \"check-spy-apps\",\n                        type: \"activity\",\n                        durationMinutes: 20,\n                        order: 1,\n                        quizQuestions: [\n                            {\n                                question: \"Where should you check for spy apps on Android?\",\n                                options: [\n                                    \"Only the home screen\",\n                                    \"Settings → Apps → Show all apps\",\n                                    \"Only the Play Store\",\n                                    \"The phone's camera\"\n                                ],\n                                correctIndex: 1,\n                                explanation: \"Spy apps hide from the home screen — you must check the full app list in Settings.\"\n                            }\n                        ],\n                        content: \"Step-by-step check:\\n\\nAndroid:\\n1. Go to Settings → Apps → Show all apps\\n2. Look for apps you do not recognise with generic names\\n3. Check for apps with device admin privileges: Settings → Security → Device admin apps\\n4. Look for accessibility services you did not enable\\n5. Check data usage: Settings → Network → Data usage — look for unknown apps using data\\n\\niPhone:\\n1. Check for unfamiliar profiles: Settings → General → VPN & Device Management\\n2. Look for apps you did not install\\n3. Check location sharing: Settings → Privacy → Location Services\\n4. Check if your iCloud account is signed in on unknown devices\\n\\nPractical Task: Complete this check on your phone right now. Remove anything suspicious.\"\n                    },\n                    {\n                        title: \"Locking Down Your Phone\",\n                        slug: \"lock-down-phone\",\n                        type: \"text\",\n                        durationMinutes: 15,\n                        order: 2,\n                        quizQuestions: [],\n                        content: \"Essential phone security:\\n\\n1. Use a strong screen lock — 6-digit PIN minimum, or biometric\\n2. Do NOT share your phone PIN with anyone\\n3. Disable 'Install from unknown sources' on Android\\n4. Keep your operating system updated\\n5. Review app permissions monthly: Settings → Privacy\\n6. Disable lock screen notification previews (prevents others reading your messages)\\n7. Enable 'Find My Phone' so you can remote-wipe if stolen\\n\\nPractical Task: Change your screen lock PIN today. Disable lock screen previews. Review your app permissions.\"\n                    },\n                    {\n                        title: \"App Permissions Audit\",\n                        slug: \"app-permissions\",\n                        type: \"activity\",\n                        durationMinutes: 15,\n                        order: 3,\n                        quizQuestions: [],\n                        content: \"Your apps may have access to more than they need.\\n\\nReview these permissions:\\n• Camera — does a calculator app need your camera? No.\\n• Microphone — does a shopping app need your mic? No.\\n• Location — does a game need your location? No.\\n• Contacts — does a flashlight app need your contacts? No.\\n\\nGo to Settings → Privacy and review each permission category. Revoke anything unnecessary.\\n\\nPractical Task: Complete a full permission audit. Remove at least 3 unnecessary permissions today.\"\n                    },\n                    {\n                        title: \"Passwords and 2FA\",\n                        slug: \"passwords-2fa\",\n                        type: \"text\",\n                        durationMinutes: 15,\n                        order: 4,\n                        quizQuestions: [\n                            {\n                                question: \"What is the safest form of two-factor authentication?\",\n                                options: [\n                                    \"SMS codes\",\n                                    \"Email codes\",\n                                    \"App-based authenticator (Google Authenticator)\",\n                                    \"Security questions\"\n                                ],\n                                correctIndex: 2,\n                                explanation: \"App-based 2FA cannot be intercepted by SIM swap attacks, unlike SMS codes.\"\n                            }\n                        ],\n                        content: \"Your password is your first line of defence.\\n\\nPassword rules:\\n• Minimum 12 characters\\n• Mix letters, numbers, symbols\\n• Never reuse passwords across accounts\\n• Never use your name, birthday, or phone number\\n• Use a password manager if possible\\n\\nTwo-Factor Authentication (2FA):\\n• Enable 2FA on every account that supports it\\n• Prefer app-based 2FA (Google Authenticator, Authy) over SMS\\n• SMS 2FA can be intercepted by SIM swap attacks\\n• Store backup codes in a safe place\\n\\nPractical Task: Enable 2FA on your email, social media, and MoMo accounts today.\"\n                    },\n                    {\n                        title: \"Phone Privacy Review Quiz\",\n                        slug: \"phone-quiz\",\n                        type: \"quiz\",\n                        durationMinutes: 10,\n                        order: 5,\n                        quizQuestions: [\n                            {\n                                question: \"What is the most common way spy apps are installed?\",\n                                options: [\n                                    \"Through phone calls\",\n                                    \"Physical access to your unlocked phone\",\n                                    \"Through Bluetooth\",\n                                    \"By sending a text message\"\n                                ],\n                                correctIndex: 1,\n                                explanation: \"Most stalkerware requires physical access to install — protect your phone lock.\"\n                            },\n                            {\n                                question: \"What should you do FIRST if you suspect your partner has installed spyware?\",\n                                options: [\n                                    \"Confront them immediately\",\n                                    \"Delete the app\",\n                                    \"Contact a trusted person for safety\",\n                                    \"Factory reset your phone\"\n                                ],\n                                correctIndex: 2,\n                                explanation: \"Ensure your physical safety first before taking any action on the device.\"\n                            },\n                            {\n                                question: \"Which password is strongest?\",\n                                options: [\n                                    \"password123\",\n                                    \"myname2024\",\n                                    \"K9#mPx$2vLqR\",\n                                    \"123456789\"\n                                ],\n                                correctIndex: 2,\n                                explanation: \"A mix of random letters, numbers, and symbols is strongest.\"\n                            }\n                        ],\n                        content: \"Complete this quiz to earn your certificate.\"\n                    }\n                ]\n            }\n        ]\n    },\n    {\n        title: \"Sextortion, Blackmail and Online Harassment Response\",\n        slug: \"sextortion-blackmail-response\",\n        excerpt: \"A practical response protocol for sextortion, blackmail, and online harassment targeting women and girls.\",\n        description: \"If someone is threatening to share your intimate images, demanding money, or harassing you online — this course gives you a step-by-step response protocol. Built by cybersecurity professionals, tested in real cases across Ghana and West Africa.\",\n        category: \"online-safety\",\n        level: \"intermediate\",\n        durationHours: 3,\n        instructor: \"DK Cyber\",\n        isFree: true,\n        isPublished: true,\n        tags: [\n            \"sextortion\",\n            \"blackmail\",\n            \"online-harassment\",\n            \"response\"\n        ],\n        learningOutcomes: [\n            \"Respond to sextortion threats without panicking\",\n            \"Preserve evidence for law enforcement\",\n            \"Report to platforms, police, and support organisations\",\n            \"Protect your accounts and digital identity after an incident\"\n        ],\n        modules: [\n            {\n                title: \"Responding to Sextortion\",\n                slug: \"sextortion-response\",\n                description: \"Step-by-step protocol when you receive a sextortion threat.\",\n                order: 0,\n                lessons: [\n                    {\n                        title: \"First 24 Hours: What To Do\",\n                        slug: \"first-24-hours\",\n                        type: \"text\",\n                        durationMinutes: 25,\n                        order: 0,\n                        quizQuestions: [],\n                        content: \"If someone is threatening to share your intimate images or demanding money, the first thing you must know is: do not pay. Paying does not make it stop.\\n\\nFirst 24 hours:\\n1. Do NOT respond to the threat\\n2. Screenshot everything — messages, profiles, demands\\n3. Do NOT delete any messages\\n4. Lock down your social media (set to private)\\n5. Tell a trusted person in your safety circle\\n6. Report to the platform where the threat was made\\n7. Contact police / Cyber Crime Unit\"\n                    }\n                ]\n            }\n        ]\n    },\n    {\n        title: \"Social Media Safety for Girls and Women\",\n        slug: \"social-media-safety\",\n        excerpt: \"Protect your identity, manage your digital footprint, and stay safe on social media platforms.\",\n        description: \"Social media is where women connect, build careers, and express themselves — but it is also where stalkers, scammers, and harassers find their targets. This course covers privacy settings, identity protection, and safe online behaviour for every major platform.\",\n        category: \"online-safety\",\n        level: \"beginner\",\n        durationHours: 3,\n        instructor: \"SafeHer Foundation\",\n        isFree: true,\n        isPublished: true,\n        tags: [\n            \"social-media\",\n            \"privacy\",\n            \"digital-safety\",\n            \"online\"\n        ],\n        learningOutcomes: [\n            \"Configure privacy settings on major social media platforms\",\n            \"Protect your identity from social engineering\",\n            \"Recognise and respond to online stalking\",\n            \"Build a safe and professional online presence\"\n        ],\n        modules: [\n            {\n                title: \"Social Media Fundamentals\",\n                slug: \"social-fundamentals\",\n                description: \"Core principles for staying safe on any platform.\",\n                order: 0,\n                lessons: [\n                    {\n                        title: \"Your Digital Footprint\",\n                        slug: \"digital-footprint\",\n                        type: \"text\",\n                        durationMinutes: 15,\n                        order: 0,\n                        quizQuestions: [],\n                        content: \"Every post, comment, photo, and check-in creates a digital footprint. This lesson shows you what information you are revealing, who can see it, and how to control your exposure.\"\n                    }\n                ]\n            }\n        ]\n    },\n    {\n        title: \"Campus and Hostel Safety\",\n        slug: \"campus-hostel-safety\",\n        excerpt: \"Safety education designed for female students living on university campuses and in hostels across Africa.\",\n        description: \"University should be the safest years of your life — but for too many women in Africa, campus brings new risks. This course covers accommodation safety, social situations, campus security resources, and emergency protocols.\",\n        category: \"campus-safety\",\n        level: \"beginner\",\n        durationHours: 4,\n        instructor: \"SafeHer Foundation\",\n        isFree: true,\n        isPublished: true,\n        tags: [\n            \"campus\",\n            \"hostel\",\n            \"university\",\n            \"students\"\n        ],\n        learningOutcomes: [\n            \"Assess and improve hostel and accommodation security\",\n            \"Navigate social situations safely\",\n            \"Use campus security and welfare resources effectively\",\n            \"Build a campus safety network with fellow students\"\n        ],\n        modules: [\n            {\n                title: \"Accommodation Security\",\n                slug: \"accommodation\",\n                description: \"Make your hostel or rental as safe as possible.\",\n                order: 0,\n                lessons: [\n                    {\n                        title: \"Choosing Safe Accommodation\",\n                        slug: \"choosing-accommodation\",\n                        type: \"text\",\n                        durationMinutes: 20,\n                        order: 0,\n                        quizQuestions: [],\n                        content: \"Where you live determines much of your safety on campus. This lesson covers what to look for when choosing accommodation — from physical security features to neighbourhood safety and proximity to emergency services.\"\n                    }\n                ]\n            }\n        ]\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/lib/sample-courses.ts\n");

